package SelJava.SelJava;

public class Q2StartPattern {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		
		int rows = 3;
		for (int i = 1; i <= rows; i++) {
            if (i == 1 || i==3) {
                System.out.println("*  *");
            } else if (i == 2) {
                System.out.println(" **");
             
        }
	}
	}
}
	


